SET @mobile_id = (SELECT id FROM courses WHERE title = 'Mobile Development' LIMIT 1);

-- Atualizar todas as aulas de Mobile com vídeos
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/0kL6nhQM6qc' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @mobile_id) AND title = 'Diferenças Web vs Mobile';
