UPDATE lessons SET video_url = 'https://www.youtube.com/embed/O6P86XQ5kQ4' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @mobile_id) AND title = 'Hooks e State Management';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/W6NZfCO5tTE' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @mobile_id) AND title = 'Dart Fundamentos';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/jBBl1RzoWDo' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @mobile_id) AND title = 'Widgets e UI em Flutter';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/Srf5S_Iicho' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @mobile_id) AND title = 'State Management em Flutter';

SELECT COUNT(*) as mobile_videos FROM lessons WHERE module_id IN (SELECT id FROM modules WHERE course_id = @mobile_id) AND video_url IS NOT NULL;

